import { useState, useEffect } from "react";
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
} from "@mui/material";
import { Edit } from "@mui/icons-material";
import DeleteIcon from "@mui/icons-material/Delete";
import ContentCopyIcon from "@mui/icons-material/ContentCopy";
import API from "../../api/axios";

export default function ProjectManagement() {
  const [search, setSearch] = useState("");
  const [data, setData] = useState([]);
  const [users, setUsers] = useState([]);

  const [open, setOpen] = useState(false);
  const [assignOpen, setAssignOpen] = useState(false);
  const [selectedProject, setSelectedProject] = useState(null);

  const [form, setForm] = useState({
    username: "",
    password: "",
    project_name: "",
    description: "",
    start_date: "",
    end_date: "",
  });

  const [createdUser, setCreatedUser] = useState(null);
  const [popupOpen, setPopupOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState("");

  const [editOpen, setEditOpen] = useState(false);
  const [editData, setEditData] = useState(null);

  // 🔄 FETCH
  const fetchProjects = async () => {
    const res = await API.get("projects/");
    setData(res.data);
  };

  const fetchUsers = async () => {
    const res = await API.get("users/");
    setUsers(res.data);
  };

  useEffect(() => {
    fetchProjects();
    fetchUsers();
  }, []);

  // 🚀 CREATE USER + PROJECT
  const createProjectUser = async () => {
    try {
      await API.post("create-project-user/", form);

      setCreatedUser({
        username: form.username,
        password: form.password,
      });

      setPopupOpen(true);
      setOpen(false);
      fetchProjects();
    } catch {
      alert("Error ❌");
    }
  };

  // ➕ ASSIGN USER
  const assignUserToProject = async () => {
    try {
      await API.post("assign-user/", {
        project_id: selectedProject.id,
        user_id: selectedUser,
      });

      setAssignOpen(false);
      fetchProjects();
    } catch {
      alert("Assign failed ❌");
    }
  };

  // ✏️ UPDATE
  const updateProject = async () => {
    await API.put(`projects/${editData.id}/`, editData);
    setEditOpen(false);
    fetchProjects();
  };

  // 🗑 DELETE
  const deleteProject = async (id) => {
    if (!window.confirm("Delete project?")) return;
    await API.delete(`projects/${id}/delete/`);
    fetchProjects();
  };

  // 📋 COPY
  const handleCopy = () => {
    navigator.clipboard.writeText(
      `Username: ${createdUser.username}\nPassword: ${createdUser.password}`,
    );
  };

  return (
    <Box sx={{ p: 4, display: "flex", justifyContent: "center" }}>
      <Paper sx={{ width: "100%", maxWidth: 1200, p: 4, borderRadius: 4 }}>
        {/* HEADER */}
        <Box sx={{ display: "flex", justifyContent: "space-between", mb: 3 }}>
          <Typography variant="h5" fontWeight="bold">
            Project Management
          </Typography>

          <Button variant="contained" onClick={() => setOpen(true)}>
            + Add User
          </Button>
        </Box>

        {/* SEARCH */}
        <TextField
          fullWidth
          placeholder="Search..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          sx={{ mb: 3 }}
        />

        {/* TABLE */}
        <Table>
          <TableHead>
            <TableRow>
              {[
                "Project",
                "Users",
                "Description",
                "Start",
                "End",
                "Actions",
              ].map((h) => (
                <TableCell key={h}>
                  <b>{h}</b>
                </TableCell>
              ))}
            </TableRow>
          </TableHead>

          <TableBody>
            {data
              .filter((d) =>
                d.project_name?.toLowerCase().includes(search.toLowerCase()),
              )
              .map((row) => (
                <TableRow key={row.id}>
                  <TableCell>{row.project_name}</TableCell>
                  <TableCell>{row.user}</TableCell>
                  <TableCell>{row.description}</TableCell>
                  <TableCell>{row.start}</TableCell>
                  <TableCell>{row.end}</TableCell>

                  <TableCell>
                    <IconButton
                      onClick={() => {
                        setEditData(row);
                        setEditOpen(true);
                      }}
                    >
                      <Edit />
                    </IconButton>

                    {/* ➕ ADD USER */}
                    <IconButton
                      onClick={() => {
                        setSelectedProject(row);
                        setAssignOpen(true);
                      }}
                    >
                      ➕
                    </IconButton>

                    <IconButton onClick={() => deleteProject(row.id)}>
                      <DeleteIcon />
                    </IconButton>
                  </TableCell>
                </TableRow>
              ))}
          </TableBody>
        </Table>

        {/* CREATE MODAL */}
        <Dialog open={open} onClose={() => setOpen(false)}>
          <DialogTitle>Create Project User</DialogTitle>
          <DialogContent>
            <TextField
              fullWidth
              label="Username"
              onChange={(e) => setForm({ ...form, username: e.target.value })}
            />
            <TextField
              fullWidth
              label="Password"
              type="password"
              onChange={(e) => setForm({ ...form, password: e.target.value })}
            />
            <TextField
              fullWidth
              label="Project"
              onChange={(e) =>
                setForm({ ...form, project_name: e.target.value })
              }
            />
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setOpen(false)}>Cancel</Button>
            <Button onClick={createProjectUser}>Create</Button>
          </DialogActions>
        </Dialog>

        {/* ASSIGN USER MODAL */}
        <Dialog open={assignOpen} onClose={() => setAssignOpen(false)}>
          <DialogTitle>Assign User</DialogTitle>
          <DialogContent>
            <Typography mb={2}>
              Project: <b>{selectedProject?.project_name}</b>
            </Typography>

            <TextField
              select
              fullWidth
              SelectProps={{ native: true }}
              value={selectedUser}
              onChange={(e) => setSelectedUser(e.target.value)}
            >
              <option value="">Select User</option>
              {users.map((u) => (
                <option key={u.id} value={u.id}>
                  {u.username}
                </option>
              ))}
            </TextField>
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setAssignOpen(false)}>Cancel</Button>
            <Button onClick={assignUserToProject}>Assign</Button>
          </DialogActions>
        </Dialog>

        {/* POPUP */}
        <Dialog open={popupOpen} onClose={() => setPopupOpen(false)}>
          <DialogContent sx={{ textAlign: "center", p: 4 }}>
            <Typography variant="h6">🎉 User Created</Typography>
            <Typography>Username: {createdUser?.username}</Typography>
            <Typography>Password: {createdUser?.password}</Typography>

            <Button
              startIcon={<ContentCopyIcon />}
              onClick={handleCopy}
              sx={{ mt: 2 }}
            >
              Copy
            </Button>
          </DialogContent>
        </Dialog>
      </Paper>
    </Box>
  );
}
